import React, { useState, useEffect } from "react";
import { Chessboard } from "react-chessboard";
import { Chess } from "chess.js";
import "./App.css";

const errorSound = new Audio("/error.mp3");
const successSound = new Audio("/success.mp3");

const eloEstimates = {
  1: 800,
  2: 1000,
  3: 1400,
  4: 1800,
  5: 2200,
  6: 2600,
  7: 3000,
};

function App() {
  const [gameStarted, setGameStarted] = useState(false);
  const [playerColor, setPlayerColor] = useState(null);
  const [game, setGame] = useState(null);
  const [fen, setFen] = useState("");
  const [gameOver, setGameOver] = useState(false);
  const [boardHighlight, setBoardHighlight] = useState("");
  const [depth, setDepth] = useState(4);
  const [engineThinking, setEngineThinking] = useState(false);
  const [message, setMessage] = useState("");

  useEffect(() => {
    if (!game) return;

    if (game.isCheckmate()) {
      setGameOver(true);
      setBoardHighlight("checkmate");
      setMessage(game.turn() === "w" ? "Black wins by checkmate!" : "White wins by checkmate!");
    } else if (game.isStalemate()) {
      setGameOver(true);
      setBoardHighlight("stalemate");
      setMessage("Stalemate!");
    } else {
      setGameOver(false);
      setBoardHighlight("");
      const isPlayerTurn = (playerColor === "white" && game.turn() === "w") || (playerColor === "black" && game.turn() === "b");
      if (!isPlayerTurn && !engineThinking) {
        makeEngineMove();
      }
    }
  }, [fen, game, playerColor, engineThinking]);

  const startGame = (color) => {
    setPlayerColor(color);
    const newGame = new Chess();
    setGame(newGame);
    setFen(newGame.fen());
    setGameStarted(true);
    setGameOver(false);
    setBoardHighlight("");
    setMessage("");
  };

  const makeEngineMove = async () => {
    setEngineThinking(true);
    try {
      const response = await fetch("http://localhost:5000/api/engine_move", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ depth }),
      });
      const data = await response.json();
      if (data.error) {
        setMessage(`Engine error: ${data.error}`);
        setEngineThinking(false);
        return;
      }
      const newGame = new Chess(data.fen);
      setGame(newGame);
      setFen(data.fen);
      successSound.play();
    } catch (error) {
      setMessage(`Connection error: ${error.message}`);
    }
    setEngineThinking(false);
  };

  const onDrop = async (sourceSquare, targetSquare) => {
    if (gameOver || engineThinking || !game) return false;

    const isPlayerTurn = (playerColor === "white" && game.turn() === "w") || (playerColor === "black" && game.turn() === "b");
    if (!isPlayerTurn) return false;

    try {
      const move = game.move({ from: sourceSquare, to: targetSquare, promotion: "q" });
      if (move === null) {
        errorSound.play();
        return false;
      }

      try {
        const response = await fetch("http://localhost:5000/api/move", {
          method: "POST",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify({ from: sourceSquare, to: targetSquare }),
        });

        if (!response.ok) {
          game.undo();
          errorSound.play();
          return false;
        }

        const data = await response.json();
        const newGame = new Chess(data.fen);
        setGame(newGame);
        setFen(data.fen);
        successSound.play();
        return true;
      } catch (error) {
        game.undo();
        setMessage(`Connection error: ${error.message}`);
        return false;
      }
    } catch (e) {
      errorSound.play();
      return false;
    }
  };

  const resetGame = () => {
    setGameStarted(false);
    setPlayerColor(null);
    setGame(null);
    setFen("");
    setGameOver(false);
    setBoardHighlight("");
    setMessage("");
  };

  if (!gameStarted) {
    return (
      <div className="app-container">
        <h1>Chess Engine</h1>
        <div className="setup-screen">
          <h2>Choose Your Color</h2>
          <button className="color-btn white-btn" onClick={() => startGame("white")}>
            Play as White
          </button>
          <button className="color-btn black-btn" onClick={() => startGame("black")}>
            Play as Black
          </button>
        </div>
      </div>
    );
  }

  return (
    <div className={`app-container ${boardHighlight}`}>
      <h1>Chess Engine</h1>
      <div className="game-info">
        <span className="player-info">You: {playerColor.toUpperCase()}</span>
        <span className="turn-info">{game && !gameOver ? `${game.turn() === "w" ? "White" : "Black"} to move` : ""}</span>
        {engineThinking && <span className="thinking-info">Engine thinking...</span>}
      </div>

      <div className={`chessboard-wrapper ${boardHighlight}`}>
        {game && (
          <Chessboard
            position={fen}
            onPieceDrop={onDrop}
            boardWidth={500}
            animationDuration={200}
            boardOrientation={playerColor === "black" ? "black" : "white"}
          />
        )}
      </div>

      <div className="controls">
        <div className="depth-control">
          <label>Engine Strength (Depth)</label>
          <input
            type="range"
            min="1"
            max="7"
            value={depth}
            onChange={(e) => setDepth(Number(e.target.value))}
            disabled={gameOver}
          />
          <div className="depth-info">
            <span>Depth: {depth}</span>
            <span className="elo-estimate">≈ {eloEstimates[depth]} ELO</span>
          </div>
        </div>

        {gameOver && (
          <div className="game-over-message">
            <h2>{boardHighlight === "checkmate" ? "Checkmate!" : "Stalemate!"}</h2>
            <p>{message}</p>
            <button onClick={resetGame} className="reset-btn">
              Play Again
            </button>
          </div>
        )}

        {message && !gameOver && <div className="message">{message}</div>}
      </div>
    </div>
  );
}

export default App;
